// MERGE do existujícího I18N_LOOKUP (z i18n_auto.js)
(function mergeIntoLookup() {
  if (typeof I18N_LOOKUP === 'undefined' || !I18N_LOOKUP) {
    console.warn('[i18n_extra] I18N_LOOKUP nenalezeno');
    return;
  }
  let merged = 0;
  for (const [lang, dict] of Object.entries(I18N_EXTRA)) {
    for (const [cs, translation] of Object.entries(dict)) {
      const existing = I18N_LOOKUP.get(cs) || {};
      existing[lang] = translation;
      I18N_LOOKUP.set(cs, existing);
      merged++;
    }
  }
  console.log('[i18n_extra] ✅ Loaded ' + merged + ' phrases in ' + Object.keys(I18N_EXTRA).length + ' languages (' + Object.keys(I18N_EXTRA).join(', ') + ')');
})();

